const items = $input.all();
const destinations = {};

// Group by destination
for (const item of items) {
  const row = item.json;
  const destName = row['Region, development group, country or area of destination'];
  const originName = row['Region, development group, country or area of origin'];
  const countStr = row['2020'];

  if (!destName || !originName || typeof countStr === 'undefined') continue;
  if (destName === originName) continue;
  if (originName.trim() === 'WORLD' || originName.trim() === 'Total') continue;

  const destClean = destName.trim();
  const originClean = originName.trim();

  // Skip regions (very rough heuristic: if there's leading spaces it's usually a country in this dataset, wait, actually UN dataset has spaces for countries to show hierarchy).
  // We will let the SQL query filter out regions because they won't match app.countries!

  // Parse count
  let count = 0;
  if (typeof countStr === 'number') count = countStr;
  else if (typeof countStr === 'string') count = parseInt(countStr.replace(/\s/g, ''), 10) || 0;

  if (!destinations[destClean]) {
    destinations[destClean] = [];
  }
  destinations[destClean].push({ origin: originClean, count: count });
}

const output = [];

// Get top 5 origins per destination
for (const dest in destinations) {
  const origins = destinations[dest];
  origins.sort((a, b) => b.count - a.count);
  const top5 = origins.slice(0, 5);

  for (const expat of top5) {
    if (expat.count > 0) {
      output.push({
        json: {
          Destination: dest,
          Origin: expat.origin,
          Count: expat.count
        }
      });
    }
  }
}

return output;
